# -- complex2real_accepts -------------------------------------------
## CVXPY SOURCE: complex2real.py lines 42-44

complex2real_accepts <- function(problem) {
  leaves <- c(variables(problem), constants(problem))
  any(vapply(leaves, is_complex, logical(1L)))
}

